16→  color: ${color.reviewText};
17→`
18→)
19→
20→type ReviewProps = {
21→  rating?: number
22→}
23→
24→const getReview = (rating?: number) => {
25→  if (!rating) {
26→    return 'No reviews yet'
27→  }
28→
29→  let reviewText = 'Very poor'
30→
31→  if (rating >= 2 && rating < 4) {
32→    reviewText = 'Adequate'
33→  } else if (rating >= 4 && rating < 5) {
34→    reviewText = 'Very good'
35→  } else if (rating >= 5) {
36→    reviewText = 'Excellent'
37→  }
38→
39→  return `★ ${rating.toFixed(1)} ${reviewText}`
40→}
41→
42→export const Review = ({ rating }: ReviewProps) => (
43→  <Wrapper>
44→    <StyledBody size="S" type="span" className="review-text">
45→      {getReview(rating)}
46→    </StyledBody>
47→  </Wrapper>
